package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

class GsonFloatAdapterTest {

  private Gson gson;
  private Method floatAdapterMethod;

  @BeforeEach
  void setUp() throws NoSuchMethodException {
    gson = new Gson();
    floatAdapterMethod = Gson.class.getDeclaredMethod("floatAdapter", boolean.class);
    floatAdapterMethod.setAccessible(true);
  }

  @Test
  void testFloatAdapter_serializeSpecialFloatingPointValuesTrue_returnsTypeAdaptersFloat() throws InvocationTargetException, IllegalAccessException {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) floatAdapterMethod.invoke(gson, true);
    assertNotNull(adapter);
    // TypeAdapters.FLOAT is public static final, so adapter should be the same instance
    // We can check the class name contains "TypeAdapters$FloatTypeAdapter" as a proxy
    assertEquals("com.google.gson.internal.bind.TypeAdapters$FloatTypeAdapter", adapter.getClass().getName());
  }

  @Test
  void testFloatAdapter_serializeSpecialFloatingPointValuesFalse_readNull() throws Exception {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) floatAdapterMethod.invoke(gson, false);

    JsonReader in = mock(JsonReader.class);
    when(in.peek()).thenReturn(JsonToken.NULL);

    Float result = (Float) adapter.read(in);
    verify(in).nextNull();
    assertNull(result);
  }

  @Test
  void testFloatAdapter_serializeSpecialFloatingPointValuesFalse_readDouble() throws Exception {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) floatAdapterMethod.invoke(gson, false);

    JsonReader in = mock(JsonReader.class);
    when(in.peek()).thenReturn(JsonToken.NUMBER);
    when(in.nextDouble()).thenReturn(123.456);

    Float result = (Float) adapter.read(in);
    assertEquals(123.456f, result);
  }

  @Test
  void testFloatAdapter_serializeSpecialFloatingPointValuesFalse_writeNull() throws Exception {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) floatAdapterMethod.invoke(gson, false);

    JsonWriter out = mock(JsonWriter.class);

    adapter.write(out, null);
    verify(out).nullValue();
  }

  @Test
  void testFloatAdapter_serializeSpecialFloatingPointValuesFalse_writeFloatValue() throws Exception {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) floatAdapterMethod.invoke(gson, false);

    JsonWriter out = mock(JsonWriter.class);

    // Use Float instance
    Float floatValue = 12.34f;
    adapter.write(out, floatValue);
    // should call out.value with the same Float instance
    verify(out).value(floatValue);

    // Use Double instance (not Float)
    reset(out);
    Double doubleValue = 56.78;
    adapter.write(out, doubleValue);
    // should call out.value with floatValue (casted)
    ArgumentCaptor<Number> captor = ArgumentCaptor.forClass(Number.class);
    verify(out).value(captor.capture());
    Number passed = captor.getValue();
    assertTrue(passed instanceof Float);
    assertEquals(doubleValue.floatValue(), passed.floatValue());
  }

  @Test
  void testFloatAdapter_serializeSpecialFloatingPointValuesFalse_writeInvalidFloatingPoint_throws() throws Exception {
    @SuppressWarnings("unchecked")
    TypeAdapter<Number> adapter = (TypeAdapter<Number>) floatAdapterMethod.invoke(gson, false);

    JsonWriter out = mock(JsonWriter.class);

    // Use NaN float value to trigger checkValidFloatingPoint exception
    Number nanValue = Float.NaN;

    IOException thrown = assertThrows(IOException.class, () -> adapter.write(out, nanValue));
    assertTrue(thrown.getMessage().contains("JSON forbids NaN and infinities"));
  }
}
